CREATE OR REPLACE FUNCTION fpb_pl_get_dep_full_amount ( as_reqno char ) RETURNS bigint AS $body$
DECLARE

ldc_full_amt  sc_lon_m_req_coll.full_amount%type;

BEGIN
  select  sum( full_amount )
  into STRICT    ldc_full_amt
  from    sc_lon_m_req_coll
  where   sc_lon_m_req_coll.loan_requestment_no = as_reqno
  and     sc_lon_m_req_coll.mustcoll_loan = '1';

  RETURN ldc_full_amt;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
